import sys
import threading
from collections import deque, defaultdict

def main():
    import sys
    sys.setrecursionlimit(1 << 25)
    input = sys.stdin.read
    data = input().split()

    idx = 0
    N = int(data[idx])
    idx += 1
    M = int(data[idx])
    idx += 1

    sets = []
    element_to_sets = defaultdict(list)

    for _ in range(N):
        A = int(data[idx])
        idx += 1
        elements = list(map(int, data[idx:idx + A]))
        idx += A
        sets.append(elements)
        for e in elements:
            element_to_sets[e].append(len(sets) - 1)

    # Check if any set already contains both 1 and M
    for s in sets:
        if 1 in s and M in s:
            print(0)
            return

    # Build graph: sets are nodes, edges between sets that share an element
    graph = [[] for _ in range(N)]
    element_to_sets_list = [set() for _ in range(M + 1)]
    for i in range(N):
        for e in sets[i]:
            element_to_sets_list[e].add(i)

    for e in range(1, M + 1):
        if len(element_to_sets_list[e]) > 1:
            sets_list = list(element_to_sets_list[e])
            for i in range(len(sets_list)):
                for j in range(i + 1, len(sets_list)):
                    graph[sets_list[i]].append(sets_list[j])
                    graph[sets_list[j]].append(sets_list[i])

    # BFS to find minimum operations to merge sets containing 1 and M
    from_1 = [-1] * N
    from_M = [-1] * N

    q = deque()
    for s in element_to_sets_list[1]:
        q.append(s)
        from_1[s] = 0
    while q:
        u = q.popleft()
        for v in graph[u]:
            if from_1[v] == -1:
                from_1[v] = from_1[u] + 1
                q.append(v)

    q = deque()
    for s in element_to_sets_list[M]:
        q.append(s)
        from_M[s] = 0
    while q:
        u = q.popleft()
        for v in graph[u]:
            if from_M[v] == -1:
                from_M[v] = from_M[u] + 1
                q.append(v)

    min_ops = float('inf')
    for i in range(N):
        if from_1[i] != -1 and from_M[i] != -1:
            min_ops = min(min_ops, from_1[i] + from_M[i])

    if min_ops == float('inf'):
        print(-1)
    else:
        print(min_ops)

threading.Thread(target=main).start()
